import { ApolloServer } from '@apollo/server';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  // no validation rules, no depth/cost analysis
});

app.use('/graphql', expressMiddleware(server));

import { ApolloServer } from '@apollo/server';
import depthLimit from 'graphql-depth-limit';
import { createComplexityRule, simpleEstimator } from 'graphql-query-complexity';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [
    depthLimit(8),
    createComplexityRule({ maximumComplexity: 1000, estimators: [simpleEstimator({ defaultComplexity: 1 })] }),
  ],
});

app.use('/graphql', expressMiddleware(server));

const server = new ApolloServer({
  typeDefs,
  resolvers,
  introspection: true,
  plugins: [ApolloServerPluginLandingPageLocalDefault()], // GraphiQL exposed
});

// NODE_ENV === 'production'

const isProd = process.env.NODE_ENV === 'production';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  introspection: !isProd,
  plugins: [isProd ? ApolloServerPluginLandingPageDisabled() : ApolloServerPluginLandingPageLocalDefault()],
});

import { ApolloServer } from '@apollo/server';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  allowBatchedHttpRequests: true,
  // no cap on operations per batch, no alias limit
});

import { ApolloServer } from '@apollo/server';
import { maxAliasesPlugin } from '@escape.tech/graphql-armor-max-aliases';
import { maxBatchPlugin } from './plugins/maxBatch';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  allowBatchedHttpRequests: true,
  plugins: [
    maxAliasesPlugin({ n: 15 }),
    maxBatchPlugin({ maxOperations: 5 }),
  ],
});
